/**
 * CopilotKit. Official wordmark (white variant) from copilotkit.ai. Embedded
 * verbatim and rendered via dangerouslySetInnerHTML so the brand artwork is
 * exact; the gradient ids are rewritten to a per-instance unique token (useId)
 * so repeated copies across slides and the print stack never collide.
 */
export function CopilotKitLogo({
  className = "",
  h = DEFAULT_H,
}: {
  className?: string;
  h?: string;
}) {
  const uid = useId().replace(/[^a-zA-Z0-9]/g, "");
  const svg = COPILOTKIT_SVG.replaceAll("5229_1726", uid);
  return (
    <span
      role="img"
      aria-label="CopilotKit"
      className={`inline-flex items-center ${h} [&>svg]:h-full [&>svg]:w-auto ${className}`}
      dangerouslySetInnerHTML={{ __html: svg }}
    />
  );
}

/**
 * The sponsor strip: a quiet eyebrow over the official marks, centered or
 * left-aligned. Weights & Biases leads and runs larger (it hosts WeaveHacks),
 * Redis is second, then OpenAI, Cursor, CopilotKit. Used on the title and close
 * slides as a bookend and at the top of the dedicated sponsors slide.
 */
export function SponsorStrip({
  label = "sponsored by",
  align = "center",
  className = "",
}: {
  label?: ReactNode;
  align?: "center" | "left";
  className?: string;
}) {
  const lead = align === "center" ? "justify-center" : "justify-start";
  return (
    <div className={className}>
      <div
        className={`mb-4 flex ${lead} font-mono text-xs uppercase tracking-[0.28em] text-slate-500`}
      >
        {label}
      </div>
      <div className={`flex flex-wrap items-center gap-x-9 gap-y-5 ${lead}`}>
        {/* Host sponsor: leads and runs larger. */}
        <WandbLogo h="h-[38px]" text="text-[20px]" gap="gap-3" />
        <RedisLogo />
        <OpenAILogo />
        <CursorLogo />
        <CopilotKitLogo />
      </div>
    </div>
  );
}
